from typing import List

class Solution:
    def canReachCorner(self, xCorner: int, yCorner: int, circles: List[List[int]]) -> bool:
        # Check if the bottom-left corner (0, 0) is blocked
        for x, y, r in circles:
            if (x - 0)**2 + (y - 0)**2 <= r**2:
                return False

        # Check if the top-right corner (xCorner, yCorner) is blocked
        for x, y, r in circles:
            if (x - xCorner)**2 + (y - yCorner)**2 <= r**2:
                return False

        # Check if any circle blocks the entire left edge (x=0) or top edge (y=yCorner)
        for x, y, r in circles:
            if y - r >= yCorner or x + r <= 0:
                continue
            if y - r <= 0:
                return False

        for x, y, r in circles:
            if y + r <= yCorner or x - r >= xCorner:
                continue
            if x - r >= 0:
                return False

        return True
